import{_ as t,o,c as i,a0 as a}from"./chunks/framework.BWpMpcZ2.js";const p=JSON.parse('{"title":"Debugging","description":"","frontmatter":{},"headers":[],"relativePath":"configuration/debugging.md","filePath":"configuration/debugging.md"}'),n={name:"configuration/debugging.md"};function r(s,e,l,d,g,c){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h1><p>margin logs every AI request and response locally so you can inspect what&#39;s happening under the hood.</p><h2 id="ai-logs" tabindex="-1">AI Logs <a class="header-anchor" href="#ai-logs" aria-label="Permalink to &quot;AI Logs&quot;">​</a></h2><p>Every time you send a request to the AI (in edit mode or chat mode), margin saves a log entry that includes:</p><ul><li>Your input prompt / instruction</li><li>The complete context sent to the writer agent (characters, styles, additional context, etc.)</li><li>The full AI response</li><li>Token usage information</li><li>Session ID and timestamp</li></ul><p>These logs are stored as JSON files in the <code>outputs/ai_logs/</code> folder inside your workspace.</p><h3 id="viewing-logs" tabindex="-1">Viewing Logs <a class="header-anchor" href="#viewing-logs" aria-label="Permalink to &quot;Viewing Logs&quot;">​</a></h3><p>You can view logs directly in the app through the <strong>AI Assist panel</strong> -- look for the log/book icon that opens the request inspector. This shows the last API request, the input and output context, the total session context, and remaining context window.</p><h3 id="editing-or-clearing-logs" tabindex="-1">Editing or Clearing Logs <a class="header-anchor" href="#editing-or-clearing-logs" aria-label="Permalink to &quot;Editing or Clearing Logs&quot;">​</a></h3><ul><li>Logs are plain JSON files -- you can open, edit, or delete them with any text editor.</li><li>To clear all logs for a session, use the delete option in the log viewer.</li></ul><div class="tip custom-block"><p class="custom-block-title">Logs are purely local. They never leave your machine.</p></div><h2 id="inspecting-prompts" tabindex="-1">Inspecting Prompts <a class="header-anchor" href="#inspecting-prompts" aria-label="Permalink to &quot;Inspecting Prompts&quot;">​</a></h2><p>The prompt templates used by the Planner and Writer agents are stored as markdown files in the <code>prompts/</code> folder at the project root:</p><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>prompts/simple-planner.md</code></td><td>Instructions for the Planner agent</td></tr><tr><td><code>prompts/simple-writer.md</code></td><td>Instructions for the Writer agent</td></tr><tr><td><code>prompts/simple-chat.md</code></td><td>Instructions for Chat mode</td></tr></tbody></table><p>You can read these files to understand exactly what instructions are being sent to the AI. Edits take effect immediately -- no restart needed.</p><div class="warning custom-block"><p class="custom-block-title">Editing prompts changes how the AI behaves. If something breaks, you can restore the original from the project&#39;s git history.</p></div><h2 id="telemetry" tabindex="-1">Telemetry <a class="header-anchor" href="#telemetry" aria-label="Permalink to &quot;Telemetry&quot;">​</a></h2><p>margin has <strong>no external telemetry</strong>. There are no analytics, no tracking scripts, and no data sent to external servers (except the AI provider you explicitly configure).</p><p>The only &quot;telemetry&quot; is local:</p><ul><li><strong>AI logs</strong> stored in <code>outputs/ai_logs/</code> for debugging your own requests</li><li><strong>Settings</strong> saved in <code>settings.json</code> at the project root</li><li><strong>No crash reports, no usage stats, no pings home</strong></li></ul><p>Everything stays on your machine.</p>',21)])])}const u=t(n,[["render",r]]);export{p as __pageData,u as default};
